import asyncio

import flyte.errors

env = flyte.TaskEnvironment("cancel")


@env.task
async def sleepers(f: float, n: int):
    await asyncio.sleep(f)


@env.task
async def failing_task(f: float):
    raise ValueError("I will fail!")


@env.task
async def main(n: int, f: float):
    sleeping_tasks = []
    for i in range(n):
        sleeping_tasks.append(asyncio.create_task(sleepers(f, i)))

    await asyncio.sleep(f)
    try:
        await failing_task(f)
        await asyncio.gather(*sleeping_tasks)
    except flyte.errors.RuntimeUserError as e:
        if e.code == "ValueError":
            print(f"Recevived Value error, canceling {len(sleeping_tasks)} sleeping tasks ")
            for t in sleeping_tasks:
                t.cancel()
        return


if __name__ == "__main__":
    flyte.init_from_config()
    print(flyte.run(main, 30, 10.0))

import flyte

env = flyte.TaskEnvironment("custom_context")


@env.task
async def downstream_task(x: int) -> int:
    custom_ctx = flyte.ctx().custom_context
    if "increment" not in custom_ctx:
        raise ValueError("Expected 'increment' in custom context")
    return x + int(custom_ctx["increment"])


@env.task
async def main(x: int) -> int:
    vals = []
    for i in range(3):
        with flyte.custom_context(increment=str(i)):
            vals.append(await downstream_task(x))
    return sum(vals)


if __name__ == "__main__":
    flyte.init_from_config()
    print(flyte.run(main, x=10).url)

import flyte

env = flyte.TaskEnvironment("data_passing")


class MyObject:
    def __init__(self, name: str, value: int):
        self.name = name
        self.value = value

    def __repr__(self):
        return f"MyObject(name={self.name}, value={self.value})"


@env.task
async def downstream_task(data: MyObject) -> dict[str, MyObject]:
    return {data.name: data}


@env.task
async def upstream_task(data: MyObject) -> dict[str, MyObject]:
    data.value += 10
    obj = await downstream_task(data)
    return obj


if __name__ == "__main__":
    flyte.init_from_config()
    obj = MyObject(name="example", value=5)
    r = flyte.run(upstream_task, data=obj)
    print(r.url)

import asyncio

import flyte

env = flyte.TaskEnvironment("env")


@env.task
async def maybe_take_a_while(x: int) -> int:
    await asyncio.sleep(x)
    return x * x


@env.task
async def fanout_calculation(ls: list[int]) -> int:
    coros = []
    with flyte.group("fanout-with-long-action"):
        for i in ls:
            coros.append(maybe_take_a_while(i))
        results = await asyncio.gather(*coros, return_exceptions=True)
        for i, res in enumerate(results):
            if isinstance(res, Exception):
                print(f"Task {i} failed with {type(res).__name__}: {res}")
            else:
                print(f"Task {i} succeeded with result: {res}")
    return sum(r for r in results if not isinstance(r, Exception))


if __name__ == "__main__":
    flyte.init_from_config()
    r = flyte.run(fanout_calculation, [1, 2, 3, 10, 100])
    print(r.url)

